record.field:
for record in records:
    if not record.x_studio_compania:
        record.write({'x_studio_compania': env.company.id})

for record in records:
    if not record.x_studio_productos:
        record.write({
            'x_studio_productos': [
                (0, 0, {
                    'x_studio_nombre_producto': 58,
                    'x_studio_cantidad': 0,
                }),
                (0, 0, {
                    'x_studio_nombre_producto': 57,
                    'x_studio_cantidad': 0,
                }),
                (0, 0, {
                    'x_studio_nombre_producto': 56,
                    'x_studio_cantidad': 0,
                }),
                (0, 0, {
                    'x_studio_nombre_producto': 54,
                    'x_studio_cantidad': 0,
                }),
                (0, 0, {
                    'x_studio_nombre_producto': 55,
                    'x_studio_cantidad': 0,
                }),
                (0, 0, {
                    'x_studio_nombre_producto': 53,
                    'x_studio_cantidad': 0,
                }),
                (0, 0, {
                    'x_studio_nombre_producto': 52,
                    'x_studio_cantidad': 0,
                }),
            ]
        })

for record in records:
    ticket_nuevo = record.x_studio_ticket_tpv_vinculado

    # Asegurar el campo nuevo en x_tickets que enlaza con el modelo independiente
    env['camping.reservamesas.setup'].sudo().setup_ticket_tpv_link_field()

    # Limpiar tickets antiguos vinculados a esta reserva nueva
    tickets_antiguos = env['x_tickets'].sudo().search([
        ('x_camping_reserva_mesa_vinculada', '=', record.id)
    ])

    if ticket_nuevo:
        tickets_antiguos = tickets_antiguos.filtered(lambda t: t.id != ticket_nuevo.id)

    for ticket in tickets_antiguos:
        ticket.write({
            'x_studio_telefono_contacto': False,
            'x_camping_reserva_mesa_vinculada': False,
            'x_studio_fecha_grupo': False,
            'x_studio_numero_personas': False,
        })

    # Escribir datos de la reserva en el ticket TPV seleccionado
    if ticket_nuevo:
        ticket_nuevo.sudo().write({
            'x_studio_telefono_contacto': record.x_studio_partner_phone or False,
            'x_camping_reserva_mesa_vinculada': record.id,
            'x_studio_fecha_grupo': record.x_studio_fecha_1 or False,
            'x_studio_numero_personas': record.x_studio_numero_personas or 0,
        })

for record in records:

    if not record.product_id:
        continue

    if record.product_id.id not in [6051, 6053]:
        continue

    if record.x_camping_reserva_mesa_vinculada:
        continue

    reserva_mesa = env['x_camping_reservamesas'].sudo().create({
        'x_name': record.partner_id.name if record.partner_id else 'Reserva sin cliente',
        'x_studio_partner_id': record.partner_id.id if record.partner_id else False,
        'x_studio_fecha_1': record.capacity_date,
        'x_studio_hora_1': 'SIN HORA',
        'x_studio_numero_adultos_1': record.adult_qty or 0,
        'x_studio_numero_ninos': record.child_qty or 0,
        'x_studio_pedido_de_venta_vinculado': record.sale_order_id.id if record.sale_order_id else False,
        'x_studio_reserva_piscina_vinculada': record.id,
    })

    record.sudo().write({
        'x_camping_reserva_mesa_vinculada': reserva_mesa.id
    })

for record in records:

    # Si está cancelada, eliminar la mesa vinculada
    if record.state == 'cancel':

        if record.x_camping_reserva_mesa_vinculada:

            reserva_mesa = record.x_camping_reserva_mesa_vinculada

            record.sudo().write({
                'x_camping_reserva_mesa_vinculada': False
            })

            reserva_mesa.sudo().unlink()

        continue

    # Si cambia a producto SIN mesa, eliminar la mesa vinculada
    if record.product_id and record.product_id.id in [6050, 6052]:

        if record.x_camping_reserva_mesa_vinculada:

            reserva_mesa = record.x_camping_reserva_mesa_vinculada

            record.sudo().write({
                'x_camping_reserva_mesa_vinculada': False
            })

            reserva_mesa.sudo().unlink()

        continue

    # Si es producto CON mesa y NO está cancelada, actualizar o crear mesa
    if record.product_id and record.product_id.id in [6051, 6053]:

        if record.x_camping_reserva_mesa_vinculada:

            record.x_camping_reserva_mesa_vinculada.sudo().write({
                'x_name': record.partner_id.name if record.partner_id else 'Reserva sin cliente',
                'x_studio_fecha_1': record.capacity_date,
                'x_studio_numero_adultos_1': record.adult_qty or 0,
                'x_studio_numero_ninos': record.child_qty or 0,
                'x_studio_partner_id': record.partner_id.id if record.partner_id else False,
                'x_studio_pedido_de_venta_vinculado': record.sale_order_id.id if record.sale_order_id else False,
                'x_studio_reserva_piscina_vinculada': record.id,
            })

        else:

            reserva_mesa = env['x_camping_reservamesas'].sudo().create({
                'x_name': record.partner_id.name if record.partner_id else 'Reserva sin cliente',
                'x_studio_partner_id': record.partner_id.id if record.partner_id else False,
                'x_studio_fecha_1': record.capacity_date,
                'x_studio_hora_1': 'SIN HORA',
                'x_studio_numero_adultos_1': record.adult_qty or 0,
                'x_studio_numero_ninos': record.child_qty or 0,
                'x_studio_pedido_de_venta_vinculado': record.sale_order_id.id if record.sale_order_id else False,
                'x_studio_reserva_piscina_vinculada': record.id,
            })

            record.sudo().write({
                'x_camping_reserva_mesa_vinculada': reserva_mesa.id
            })

today = datetime.date.today()
reservas = env['x_camping_reservamesas'].sudo().search([
    ('x_studio_fecha_1', '=', today),
], order='x_studio_hora_1 asc, x_name asc')
if reservas:
    informe = env.ref('odoo_restaurant_table_reservation.reservamesas_informe_59ff79a0-138c-4cef-a7f8-6f8a7d89043f').sudo()
    pdf_content, content_type = informe._render_qweb_pdf(informe.report_name, reservas.ids)
    fecha_txt = today.strftime('%d-%m-%Y')
    nombre = 'ticketmesas-' + fecha_txt + '.pdf'
    adjunto = env['ir.attachment'].sudo().create({
        'name': nombre,
        'type': 'binary',
        'datas': b64encode(pdf_content).decode('utf-8'),
        'res_model': 'x_camping_reservamesas',
        'res_id': reservas.ids and reservas.ids[0] or False,
        'mimetype': 'application/pdf',
    })
    action = {
        'type': 'ir.actions.act_url',
        'url': '/web/content/' + str(adjunto.id) + '?download=true',
        'target': 'self',
    }
else:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Sin reservas',
            'message': 'No hay reservas de mesa para imprimir en la fecha de hoy.',
            'type': 'warning',
            'sticky': False,
        }
    }
